var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX 3: ValidateScopes — scoped IUserService cannot be resolved from singleton.
// Inject IServiceScopeFactory instead of resolving scoped service from root container.
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IServiceScopeFactory>()));
// FIX 1: HttpClientFactory now uses SocketsHttpHandler by default.
// Direct cast to HttpClientHandler throws InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// FIX 2: HttpClientFactory now redacts all header values in Trace-level logs.
// Allowlist specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // FIX 4: ForwardedHeaders middleware now ignores X-Forwarded-* from unknown proxies.
    // Add your trusted reverse proxy addresses here.
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

